package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testGetIgnoreSurroundingSpaces() {
        // Given
        boolean expected = true;

        // When
        boolean result = csvFormat.getIgnoreSurroundingSpaces();

        // Then
        assertEquals(expected, result);
    }

    @Test
    public void testGetIgnoreSurroundingSpacesFalse() {
        // Given
        CSVFormat csvFormatMock = mock(CSVFormat.class);
        when(csvFormatMock.getIgnoreSurroundingSpaces()).thenReturn(false);

        // When
        boolean result = csvFormatMock.getIgnoreSurroundingSpaces();

        // Then
        assertEquals(false, result);
    }
}
